#[derive(Clone, Copy, Debug, Eq, Hash, PartialEq)]
pub struct WoodenDoor {
    door_hinge_bit: bool,
    cardinal_direction: CardinalDirection,
    open_bit: bool,
    upper_block_bit: bool,
}

impl WoodenDoor {
    pub const DEFAULT: Self = Self {
        door_hinge_bit: false,
        cardinal_direction: CardinalDirection::East,
        open_bit: false,
        upper_block_bit: false,
    };

    pub const fn new() -> Self {
        Self::DEFAULT
    }

    pub const fn with_door_hinge_bit(mut self, door_hinge_bit: bool) -> Self {
        self.door_hinge_bit = door_hinge_bit;
        self
    }

    pub const fn with_cardinal_direction(mut self, cardinal_direction: CardinalDirection) -> Self {
        self.cardinal_direction = cardinal_direction;
        self
    }

    pub const fn with_open_bit(mut self, open_bit: bool) -> Self {
        self.open_bit = open_bit;
        self
    }

    pub const fn with_upper_block_bit(mut self, upper_block_bit: bool) -> Self {
        self.upper_block_bit = upper_block_bit;
        self
    }
}

impl Default for WoodenDoor {
    fn default() -> Self {
        Self::DEFAULT
    }
}

impl From<WoodenDoor> for Block {
    fn from(value: WoodenDoor) -> Self {
        Block::from_properties(
            "minecraft:wooden_door",
            [
                ("door_hinge_bit", Property::Bool(value.door_hinge_bit)),
                (
                    "minecraft:cardinal_direction",
                    Property::String(value.cardinal_direction.as_str().to_owned()),
                ),
                ("open_bit", Property::Bool(value.open_bit)),
                ("upper_block_bit", Property::Bool(value.upper_block_bit)),
            ],
        )
    }
}

